// TCP/IP Stack Katmanları

// Application Layer (HTTP, FTP, DNS, SMTP)
GET /index.html HTTP/1.1
Host: example.com

// Transport Layer (TCP/UDP)
[TCP Header: Source Port, Dest Port, Seq, Ack, Flags]

// Internet Layer (IP)
[IP Header: Source IP, Dest IP, TTL, Protocol]

// Link Layer (Ethernet)
[Ethernet Header: Source MAC, Dest MAC, Type]

// Paket yapısı:
// [Ethernet][IP][TCP][HTTP Data][Ethernet Trailer]

// Her katman bir sonrakini kapsüller:
// HTTP data -> TCP segment -> IP packet -> Ethernet frame

// NAT çalışma prensibi

// İç ağdan dışarı (Outbound)
Private: 192.168.1.100:5000 -> google.com:443
NAT:     203.0.113.5:12345  -> google.com:443
// Router, 192.168.1.100:5000 <-> 12345 mapping'i tutar

// Dışarıdan içeri (Inbound - Port Forwarding)
External: 203.0.113.5:80 -> 192.168.1.10:8080
// Port 80'e gelen istekler 192.168.1.10:8080'e yönlendirilir

// iptables ile NAT (Linux)
sudo iptables -t nat -A POSTROUTING -o eth0 -j MASQUERADE

// Port forwarding
sudo iptables -t nat -A PREROUTING -p tcp --dport 80 \
  -j DNAT --to-destination 192.168.1.10:8080

// TCP handshake süreci

// 1. SYN
Client -> Server: SYN, Seq=100

// 2. SYN-ACK
Server -> Client: SYN-ACK, Seq=300, Ack=101

// 3. ACK
Client -> Server: ACK, Seq=101, Ack=301

// Bağlantı kuruldu, veri akışı başlar

// Bağlantı kapatma
Client -> Server: FIN, Seq=500
Server -> Client: ACK, Ack=501
Server -> Client: FIN, Seq=800
Client -> Server: ACK, Ack=801

// tcpdump ile görüntüleme
$ sudo tcpdump -i eth0 'tcp[tcpflags] & (tcp-syn) != 0'

// netstat ile bağlantı durumları
$ netstat -an | grep ESTABLISHED
$ netstat -an | grep TIME_WAIT

// TCP window size
Client -> Server: Data (Seq=1000, Len=1000, Win=65535)
Server -> Client: ACK (Ack=2000, Win=32768)
// Server, 32KB daha kabul edebilir

// Congestion control durumları
1. Slow Start: cwnd exponential artar
2. Congestion Avoidance: cwnd linear artar
3. Fast Retransmit: 3 duplicate ACK -> hemen yeniden gönder
4. Fast Recovery: cwnd'yi yarıya düşür

// Linux TCP ayarları
$ sysctl net.ipv4.tcp_congestion_control
net.ipv4.tcp_congestion_control = cubic

// Değiştirme
$ sudo sysctl -w net.ipv4.tcp_congestion_control=bbr

// TCP istatistikleri
$ ss -ti
  cubic wscale:7,7 rto:204 rtt:3.5/1.5 cwnd:10

// REST API örnekleri

// Kullanıcıları listele
GET /api/v1/users?page=1&limit=20&sort=created_at

// Tek kullanıcı
GET /api/v1/users/123

// Yeni kullanıcı oluştur
POST /api/v1/users
Content-Type: application/json

{"name": "Ahmet", "email": "ahmet@example.com"}

// Kullanıcı güncelle
PUT /api/v1/users/123
{"name": "Ahmet Yılmaz"}

// Kısmi güncelleme
PATCH /api/v1/users/123
{"email": "yeni@example.com"}

// Kullanıcı sil
DELETE /api/v1/users/123

// Nested resources
GET /api/v1/users/123/posts
POST /api/v1/users/123/posts

// Hata response
{
  "error": {
    "code": "VALIDATION_ERROR",
    "message": "Email is required",
    "field": "email"
  }
}

// DNS record örnekleri

// A record
example.com.  3600  IN  A  93.184.216.34

// AAAA record (IPv6)
example.com.  3600  IN  AAAA  2606:2800:220:1:248:1893:25c8:1946

// CNAME record
www.example.com.  3600  IN  CNAME  example.com.

// MX record
example.com.  3600  IN  MX  10 mail1.example.com.
example.com.  3600  IN  MX  20 mail2.example.com.

// TXT record
example.com.  3600  IN  TXT  "v=spf1 include:_spf.google.com ~all"

// NS record
example.com.  3600  IN  NS  ns1.example.com.
example.com.  3600  IN  NS  ns2.example.com.

// SOA record
example.com.  3600  IN  SOA  ns1.example.com. admin.example.com. (
                              2024010101 ; Serial
                              3600       ; Refresh
                              1800       ; Retry
                              604800     ; Expire
                              86400 )    ; Minimum TTL

// DNSSEC doğrulama
$ dig +dnssec example.com

;; ANSWER SECTION:
example.com.  3600  IN  A  93.184.216.34
example.com.  3600  IN  RRSIG  A 13 2 3600 ...

// DNS over HTTPS (DoH)
$ curl -H 'accept: application/dns-json' \
  'https://cloudflare-dns.com/dns-query?name=example.com&type=A'

// DNS over TLS (DoT) test
$ kdig -d @1.1.1.1 +tls example.com

// DNS cache poisoning testi
$ dig @vulnerable-dns-server.com attacker.com

// Güvenli DNS sunucuları
Cloudflare: 1.1.1.1, 1.0.0.1
Google: 8.8.8.8, 8.8.4.4
Quad9: 9.9.9.9
